#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use HTML::Entities qw(encode_entities);

my $log_dir = '/var/log';
my $filename = param('logfile') // '';

$filename =~ s/^\s+|\s+$//g;
$filename =~ s/[^A-Za-z0-9._-]//g;

print header(-type => 'text/html', -charset => 'UTF-8');

print "<!DOCTYPE html>\n<html><head><title>Log Viewer</title></head><body>\n";

if ($filename eq '') {
    print "<p>No logfile specified.</p>\n";
    print "</body></html>\n";
    exit;
}

my $path = "$log_dir/$filename";

if (!open(FH, "$path")) {
    print "<p>Unable to open log file: ", encode_entities($filename), "</p>\n";
    print "</body></html>\n";
    exit;
}

print "<pre>\n";
while (my $line = <FH>) {
    print encode_entities($line);
}
print "</pre>\n";

close(FH);

print "</body></html>\n";